mapper.select:
SELECT
    a.id,
    a.original_filename,
    a.filename,
    a.ext,
    a.size,
    a.object_key,
    a.file_source,
    a.equipment_id,
    a.source_file_md5,
    a.file_md5,
    a.create_user,
    a.create_time,
    a.is_encrypt,
    a.encrypt_key,
    a.encrypt_type,
    a.encrypt_len,
    CONCAT(b.storage_address,'/',b.bucket,'/',a.object_key) AS url,
    b.bucket AS bucket_name,
    CONCAT(b.bucket,'/',a.object_key) AS file_path
FROM st_file a
    JOIN st_equipment b ON b.id = a.equipment_id AND b.is_deleted = 0

    a.is_deleted = 0
    
        AND a.id = #{id}
    
    
        AND original_filename = #{originalFilename}
    
    
        AND filename = #{filename}
    
    
        AND ext = #{ext}
    
    
        AND size = #{size}
    
    
        AND object_key = #{objectKey}
    
    
        AND file_source = #{fileSource}
    
    
        AND equipment_id = #{equipmentId}
    
    
        AND source_file_md5 = #{sourceFileMd5}
    
    
        AND file_md5 = #{fileMd5}
    
    
        AND create_user = #{createUser}
    
    
        AND create_time = #{createTime}
    
    
        AND is_deleted = #{isDeleted}
    
    
        AND is_encrypt = #{isEncrypt}
    
    
        AND encrypt_type = #{encryptType}
    
    
        AND encrypt_len = #{encryptLen}
    

ORDER BY a.create_time DESC

SELECT a.id, a.original_filename, a.filename, a.ext, a.size, a.object_key, a.file_source, a.equipment_id, a.source_file_md5, a.file_md5, a.create_user, a.create_time, a.is_encrypt, a.encrypt_key, a.encrypt_type, a.encrypt_len, CONCAT(b.storage_address,'/',b.bucket,'/',a.object_key) AS url, b.bucket AS bucket_name, CONCAT(b.bucket,'/',a.object_key) AS file_path FROM st_file a JOIN st_equipment b ON b.id = a.equipment_id AND b.is_deleted = 0 WHERE a.is_deleted = 0 AND a.id IN
#{id}
ORDER BY FIELD(a.id ,
#{id}
);

SELECT
a."ID", a."ORIGINAL_FILENAME", a."FILENAME", a."EXT", a."SIZE", a."OBJECT_KEY",
a."FILE_SOURCE", a."EQUIPMENT_ID", a."SOURCE_FILE_MD5", a."FILE_MD5",
a."CREATE_USER", a."CREATE_TIME", a."IS_ENCRYPT", a."ENCRYPT_KEY",
a."ENCRYPT_TYPE", a."ENCRYPT_LEN",
(b."STORAGE_ADDRESS" || '/' || b."BUCKET" || '/' || a."OBJECT_KEY") AS url,
b."BUCKET" AS bucket_name,
(b."BUCKET" || '/' || a."OBJECT_KEY") AS file_path
FROM st_file a
JOIN st_equipment b ON b."ID" = a."EQUIPMENT_ID" AND b."IS_DELETED" = 0

    a."IS_DELETED" = 0
    AND a."ID" = #{id}
    AND a."ORIGINAL_FILENAME" = #{originalFilename}
    AND a."FILENAME" = #{filename}
    AND a."EXT" = #{ext}
    AND a."SIZE" = #{size}
    AND a."OBJECT_KEY" = #{objectKey}
    AND a."FILE_SOURCE" = #{fileSource}
    AND a."EQUIPMENT_ID" = #{equipmentId}
    AND a."SOURCE_FILE_MD5" = #{sourceFileMd5}
    AND a."FILE_MD5" = #{fileMd5}
    AND a."CREATE_USER" = #{createUser}
    AND a."CREATE_TIME" = #{createTime}
    AND a."IS_DELETED" = #{isDeleted}
    AND a."IS_ENCRYPT" = #{isEncrypt}
    AND a."ENCRYPT_TYPE" = #{encryptType}
    AND a."ENCRYPT_LEN" = #{encryptLen}

ORDER BY a."CREATE_TIME" DESC

SELECT a."ID", a."ORIGINAL_FILENAME", a."FILENAME", a."EXT", a."SIZE", a."OBJECT_KEY", a."FILE_SOURCE", a."EQUIPMENT_ID", a."SOURCE_FILE_MD5", a."FILE_MD5", a."CREATE_USER", a."CREATE_TIME", a."IS_ENCRYPT", a."ENCRYPT_KEY", a."ENCRYPT_TYPE", a."ENCRYPT_LEN" FROM st_file a
a."IS_DELETED" = 0
AND a."ID" IN #{id}
